#!/bin/bash
#
# data_root/split_root/checkpoint/output-root paths come from HiVG/.env
# (see _load_env.sh) -- copy HiVG/.env.example to HiVG/.env and fill it in.
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "$SCRIPT_DIR/_load_env.sh"


CUDA_VISIBLE_DEVICES=1,2,3,4,5,6,7 python -m torch.distributed.launch --nproc_per_node=7 --master_port 28887 --use_env hivg_train.py --num_workers 4 --epochs 10 --batch_size 32 --lr 0.00025  --lr_scheduler cosine --aug_crop --aug_scale --aug_translate --model ViT-L/14  --vl_hidden_dim 768 --imsize 224 --max_query_len 77 --normalize_before --dataset gref_umd --warmup --use_contrastive_loss  --use_csc_constrain_loss --use_mask_loss  --data_root $DATA_ROOT --split_root $SPLIT_ROOT --clip_model $CLIP_CKPT_LARGE  --output_dir $OUT_ROOT/output_v100_warm/gref_umd --sup_type full;

